import React, { useState, useEffect } from 'react';
import { EntranceStorage, StorageTypeRecord } from '../types';
import { STORAGE_CATEGORIES, COLORS, DAIWA_PRICES, getStorageDetailPdfUrl } from '../constants';

interface EntranceStorageSectionProps {
  storage: EntranceStorage;
  updateStorage: (updates: Partial<EntranceStorage>) => void;
  siteName: string;
  storageTypes: StorageTypeRecord[];
}

export const EntranceStorageSection: React.FC<EntranceStorageSectionProps> = ({ storage, updateStorage, siteName, storageTypes }) => {
  const initialCategory = storageTypes.find(s => s.id === storage.type)?.category || "なし";
  const [selectedCategory, setSelectedCategory] = useState(initialCategory);
  const [isFillerInfoOpen, setIsFillerInfoOpen] = useState(false);
  const [isDaiwaInfoOpen, setIsDaiwaInfoOpen] = useState(false);
  const [isMirrorInfoOpen, setIsMirrorInfoOpen] = useState(false);

  const filteredTypes = storageTypes.filter(s => s.category === selectedCategory);
  const mirrorIncompatibleCategories = ["一の字タイプ", "二の字タイプ"];

  const handleOpenDetails = () => {
    let finalUrl = '';
    let isPdf = false;

    const record = storageTypes.find(s => s.id === storage.type);

    if (record && record.imageUrl) {
      finalUrl = record.imageUrl;
    } else {
      finalUrl = getStorageDetailPdfUrl(storage.type);
    }

    isPdf = finalUrl.toLowerCase().endsWith('.pdf');

    const printWindow = window.open('', '_blank');
    if (!printWindow) {
      alert('ポップアップがブロックされました。ブラウザの設定を確認してください。');
      return;
    }

    const htmlContent = `
      <!DOCTYPE html>
      <html lang="ja">
      <head>
        <meta charset="UTF-8">
        <title>玄関収納詳細図面 - ${storage.size}</title>
        <style>
          @page { size: A3 landscape; margin: 0; }
          body { 
            margin: 0; 
            padding: 0; 
            background: #eee;
            -webkit-print-color-adjust: exact; 
            print-color-adjust: exact; 
            font-family: 'Noto Sans JP', sans-serif;
            overflow: hidden;
          }
          .page-container {
            width: 420mm;
            height: 297mm;
            position: relative;
            background-color: white;
            margin: 0 auto;
            overflow: hidden;
          }
          .background-media {
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            z-index: 1;
          }
          .background-image {
            width: 100%;
            height: 100%;
            background-image: url('${finalUrl}');
            background-size: contain;
            background-repeat: no-repeat;
            background-position: center;
          }
          .background-pdf {
            width: 100%;
            height: 100%;
            border: none;
          }
          .overlay-header {
            position: absolute;
            top: 15mm;
            left: 15mm;
            display: flex;
            align-items: stretch;
            z-index: 100;
            background: rgba(255, 255, 255, 0.85);
            padding: 4mm 8mm;
            border-radius: 12px;
            box-shadow: 0 8px 16px rgba(0,0,0,0.1);
            border: 1px solid #ddd;
          }
          .id-box {
            padding: 2mm 6mm;
            font-size: 32pt;
            font-weight: 900;
            color: #ea580c; 
            display: flex;
            align-items: center;
            justify-content: center;
            min-width: 40mm;
            border-right: 2px solid #ddd;
            margin-right: 6mm;
          }
          .details-box {
            padding: 1mm 2mm;
            display: flex;
            flex-direction: column;
            justify-content: center;
            min-width: 120mm;
          }
          .details-row {
            display: flex;
            align-items: center;
            gap: 6mm;
            line-height: 1.4;
          }
          .details-item {
            display: flex;
            gap: 2mm;
            align-items: baseline;
          }
          .details-label {
            color: #555;
            font-size: 9pt;
            white-space: nowrap;
          }
          .details-value {
            font-weight: 800;
            font-size: 13pt;
            color: #000;
          }
          .no-print-bar {
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            background: #1f2937;
            color: white;
            padding: 10px 20px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            z-index: 1000;
          }
          .print-btn {
            background: #2563eb;
            color: white;
            border: none;
            padding: 10px 24px;
            border-radius: 6px;
            cursor: pointer;
            font-weight: bold;
            font-size: 14px;
          }
          @media print {
            .no-print-bar { display: none; }
            body { background: white; }
            .page-container { margin: 0; }
          }
        </style>
      </head>
      <body>
        <div class="no-print-bar">
          <span>図面プレビュー: ${storage.size} (${siteName || '現場名未設定'})</span>
          <button class="print-btn" onclick="window.print()">印刷 / PDF保存</button>
        </div>
        <div class="page-container">
          <div class="background-media">
             ${isPdf 
              ? `<iframe src="${finalUrl}#toolbar=0&navpanes=0&scrollbar=0&view=FitH" class="background-pdf"></iframe>`
              : `<div class="background-image"></div>`
            }
          </div>
          <div class="overlay-header">
            <div class="id-box">GS</div>
            <div class="details-box">
              <div class="details-row">
                <div class="details-item">
                  <span class="details-label">物件名</span>
                  <span class="details-value">${siteName || '○○様邸'}</span>
                </div>
                <div class="details-item">
                  <span class="details-label">種類</span>
                  <span class="details-value">${selectedCategory}</span>
                </div>
              </div>
              <div class="details-row" style="margin-top: 2mm;">
                <div class="details-item">
                  <span class="details-label">仕様</span>
                  <span class="details-value">${storage.size}</span>
                </div>
                <div class="details-item">
                  <span class="details-label">カラー</span>
                  <span class="details-value">${storage.color}</span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </body>
      </html>
    `;

    printWindow.document.write(htmlContent);
    printWindow.document.close();
  };

  const handleCategoryChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const newCategory = e.target.value;
    setSelectedCategory(newCategory);

    if (newCategory === "なし") {
      updateStorage({
        type: "NONE",
        size: "なし",
        basePrice: 0,
        baseRing: "なし",
        baseRingPrice: 0,
        mirror: "なし",
        mirrorPrice: 0,
        fillerPrice: 0,
        fillerCount: 0
      });
    } else {
      const firstInCat = storageTypes.find(s => s.category === newCategory);
      if (firstInCat) {
        const updates: Partial<EntranceStorage> = {
          type: firstInCat.id,
          size: firstInCat.name,
          basePrice: firstInCat.price,
          baseRingPrice: storage.baseRing !== "なし" ? (DAIWA_PRICES[firstInCat.width] || 0) : 0
        };

        if (mirrorIncompatibleCategories.includes(newCategory)) {
          updates.mirror = "なし";
          updates.mirrorPrice = 0;
        }

        updateStorage(updates);
      }
    }
  };

  const handleTypeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const selected = storageTypes.find(s => s.id === e.target.value);
    if (selected) {
      updateStorage({
        type: selected.id,
        size: selected.name,
        basePrice: selected.price,
        baseRingPrice: storage.baseRing !== "なし" ? (DAIWA_PRICES[selected.width] || 0) : 0
      });
    }
  };

  const handleBaseRingToggle = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const hasBaseRing = e.target.value === "あり";
    const selected = storageTypes.find(s => s.id === storage.type);
    const width = selected?.width || 0;

    updateStorage({
      baseRing: e.target.value,
      baseRingPrice: hasBaseRing ? (DAIWA_PRICES[width] || 0) : 0
    });
  };

  const isNone = storage.type === 'NONE';
  const isMirrorDisabled = isNone || mirrorIncompatibleCategories.includes(selectedCategory);

  const total = isNone ? 0 : (storage.basePrice + storage.baseRingPrice + (storage.fillerPrice * storage.fillerCount) + storage.mirrorPrice);

  const Modal = ({ isOpen, onClose, title, imageUrl, children }: { isOpen: boolean, onClose: () => void, title: string, imageUrl?: string, children?: React.ReactNode }) => {
    if (!isOpen) return null;
    return (
      <div 
        className="fixed inset-0 z-[200] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 no-print"
        onClick={onClose}
      >
        <div 
          className="bg-white p-6 rounded-2xl shadow-2xl max-w-md w-full animate-in zoom-in duration-200 overflow-hidden"
          onClick={(e) => e.stopPropagation()}
        >
          <div className="flex justify-between items-center mb-4">
            <h4 className="text-lg font-bold text-gray-800">{title}</h4>
            <button onClick={onClose} className="text-gray-400 hover:text-gray-600">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>
          {imageUrl && <img src={imageUrl} alt={title} className="w-full h-auto rounded-lg mb-4 max-h-[60vh] object-contain" />}
          {children}
          <div className="mt-6 flex justify-end">
            <button 
              onClick={onClose}
              className="bg-gray-100 hover:bg-gray-200 text-gray-700 px-6 py-2 rounded-lg text-sm font-bold transition-colors"
            >
              閉じる
            </button>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className={`bg-white rounded-lg shadow-sm border border-gray-200 p-4 mb-6 print-break-inside-avoid ${isNone ? 'opacity-70' : ''}`}>
      <Modal isOpen={isFillerInfoOpen} onClose={() => setIsFillerInfoOpen(false)} title="フィラー（幕板）について">
        <p className="text-gray-600 leading-relaxed text-sm mb-4">
          「フィラー（幕板）」とは、玄関収納と壁の間に取り付ける隙間を埋めるための板。扉の開閉が完全に行なわれるようにする役割もあります。
        </p>
        <div className="bg-blue-50 p-5 rounded-xl border border-blue-100 space-y-4 text-xs text-gray-700">
          <div>
            <p className="font-bold text-blue-900 border-b border-blue-200 pb-1 mb-2">フィラーセット サイズ 60×18×長さ</p>
          </div>
          <div>
            <p className="font-bold text-gray-900 flex justify-between">
              <span>セパレートタイプセット</span>
              <span className="text-blue-700 font-bold">2,000円</span>
            </p>
            <p className="mt-1">長さ＝900㎜/1本　長さ400㎜/2本</p>
          </div>
          <div className="pt-2">
            <p className="font-bold text-gray-900 flex justify-between">
              <span>トールタイプセット</span>
              <span className="text-blue-700 font-bold">2,000円</span>
            </p>
            <p className="mt-1">長さ＝2100㎜/１本　長さ＝400㎜/2本</p>
          </div>
        </div>
      </Modal>

      <Modal isOpen={isDaiwaInfoOpen} onClose={() => setIsDaiwaInfoOpen(false)} title="台輪について" imageUrl="http://25663cc9bda9549d.main.jp/aistudio/door/daiwa.jpg">
        <p className="text-xs text-gray-500">玄関収納本体を支える下部パーツです。</p>
      </Modal>

      <Modal isOpen={isMirrorInfoOpen} onClose={() => setIsMirrorInfoOpen(false)} title="ミラーについて" imageUrl="http://25663cc9bda9549d.main.jp/aistudio/door/mirror.JPG">
        <p className="text-xs text-gray-500">扉に設置される全身鏡オプションです。</p>
      </Modal>

      <div className="flex justify-between items-center mb-4 border-l-4 border-orange-500 pl-3">
        <h3 className="text-xl font-bold text-gray-800">玄関収納</h3>
        <button
          onClick={(e) => {
            e.preventDefault();
            handleOpenDetails();
          }}
          disabled={isNone}
          className={`no-print px-4 py-1.5 rounded-lg text-xs font-bold transition-all shadow-md active:scale-95 whitespace-nowrap flex items-center gap-2 ${isNone ? 'bg-gray-100 text-gray-300 cursor-not-allowed shadow-none border border-gray-100' : 'bg-blue-600 hover:bg-blue-700 text-white'}`}
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 18l-6-6m0 0l6-6m-6 6h18" />
          </svg>
          玄関収納 詳細図面
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-12 gap-4 text-sm">
        <div className="space-y-1 lg:col-span-2">
          <label className="block text-xs font-semibold text-gray-500">カテゴリー</label>
          <select
            value={selectedCategory}
            onChange={handleCategoryChange}
            className="w-full border rounded px-2 py-1.5 focus:ring-1 focus:ring-blue-500 bg-white"
          >
            {STORAGE_CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>

        <div className="space-y-1 lg:col-span-4">
          <label className={`block text-xs font-semibold ${isNone ? 'text-gray-300' : 'text-gray-500'}`}>タイプ / サイズ</label>
          <select
            value={storage.type}
            disabled={isNone}
            onChange={handleTypeChange}
            className={`w-full border rounded px-2 py-1.5 focus:ring-1 focus:ring-blue-500 ${isNone ? 'bg-gray-50 text-gray-400 border-gray-100' : 'bg-white font-medium text-gray-800'}`}
          >
            {isNone ? <option value="NONE">なし</option> : filteredTypes.map(s => <option key={s.id} value={s.id}>{s.name} (¥{s.price.toLocaleString()})</option>)}
          </select>
        </div>

        <div className="space-y-1 lg:col-span-2">
          <label className={`block text-xs font-semibold ${isNone ? 'text-gray-300' : 'text-gray-500'}`}>扉カラー</label>
          <select
            value={storage.color}
            disabled={isNone}
            onChange={(e) => updateStorage({ color: e.target.value })}
            className={`w-full border rounded px-2 py-1.5 focus:ring-1 focus:ring-blue-500 ${isNone ? 'bg-gray-50 text-gray-400 border-gray-100' : 'bg-white'}`}
          >
            {COLORS.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>

        <div className="space-y-1 lg:col-span-4 grid grid-cols-7 gap-2">
          <div className="col-span-2">
            <div className="flex items-center gap-1 mb-1">
              <label className={`block text-xs font-semibold ${isNone ? 'text-gray-300' : 'text-gray-500'}`}>台輪</label>
              <button 
                onClick={() => setIsDaiwaInfoOpen(true)}
                disabled={isNone}
                className={`no-print bg-blue-500 hover:bg-blue-400 text-white rounded-full w-4 h-4 flex items-center justify-center text-[10px] transition-colors shadow-sm ${isNone ? 'opacity-30 cursor-not-allowed' : ''}`}
                title="台輪の画像を表示"
              >
                i
              </button>
            </div>
            <select
              value={storage.baseRingPrice > 0 ? "あり" : "なし"}
              disabled={isNone}
              onChange={handleBaseRingToggle}
              className={`w-full border rounded px-1 py-1.5 text-sm focus:ring-1 focus:ring-blue-500 ${isNone ? 'bg-gray-50 text-gray-400 border-gray-100' : 'bg-white'}`}
            >
              <option value="なし">なし</option>
              <option value="あり">あり (¥{storage.baseRingPrice.toLocaleString() || '-'})</option>
            </select>
          </div>
          <div className="col-span-2">
            <div className="flex items-center gap-1 mb-1">
              <label className={`block text-xs font-semibold ${isMirrorDisabled ? 'text-gray-300' : 'text-gray-500'}`}>ミラー</label>
              <button 
                onClick={() => setIsMirrorInfoOpen(true)}
                disabled={isMirrorDisabled}
                className={`no-print bg-blue-500 hover:bg-blue-400 text-white rounded-full w-4 h-4 flex items-center justify-center text-[10px] transition-colors shadow-sm ${isMirrorDisabled ? 'opacity-30 cursor-not-allowed' : ''}`}
                title="ミラーの画像を表示"
              >
                i
              </button>
            </div>
            <select
              value={storage.mirror}
              disabled={isMirrorDisabled}
              onChange={(e) => updateStorage({ mirror: e.target.value, mirrorPrice: e.target.value === 'あり' ? 10400 : 0 })}
              className={`w-full border rounded px-1 py-1.5 text-sm focus:ring-1 focus:ring-blue-500 ${isMirrorDisabled ? 'bg-gray-50 text-gray-400 border-gray-100 cursor-not-allowed' : 'bg-white'}`}
            >
              <option value="なし">なし</option>
              {!isMirrorDisabled && <option value="あり">あり (+¥10,400)</option>}
            </select>
          </div>
          <div className="col-span-3">
            <div className="flex items-center gap-1 mb-1">
              <label className={`block text-xs font-semibold ${isNone ? 'text-gray-300' : 'text-gray-500'}`}>フィラー</label>
              <button 
                onClick={() => setIsFillerInfoOpen(true)}
                disabled={isNone}
                className={`no-print bg-blue-500 hover:bg-blue-400 text-white rounded-full w-4 h-4 flex items-center justify-center text-[10px] transition-colors shadow-sm ${isNone ? 'opacity-30 cursor-not-allowed' : ''}`}
                title="フィラーの説明を表示"
              >
                i
              </button>
            </div>
            <div className="flex items-center gap-1">
              <input
                type="number"
                min="0"
                value={storage.fillerCount}
                disabled={isNone}
                onChange={(e) => {
                  const count = Math.max(0, parseInt(e.target.value) || 0);
                  updateStorage({ fillerCount: count, fillerPrice: 2000 });
                }}
                className={`w-[40%] border rounded px-1 py-1.5 text-sm text-center focus:ring-1 focus:ring-blue-500 ${isNone ? 'bg-gray-50 text-gray-400 border-gray-100' : 'bg-white'}`}
              />
              <span className={`text-sm ${isNone ? 'text-gray-300' : 'text-gray-400'} whitespace-nowrap`}>個</span>
            </div>
          </div>
        </div>
      </div>

      <div className="mt-4 flex justify-between items-center border-t border-gray-100 pt-3">
        <div className="text-sm text-gray-900 font-bold">
          {!isNone && (
            <div className="flex gap-4">
              <span>本体: ¥{storage.basePrice.toLocaleString()}</span>
              {storage.baseRingPrice > 0 && <span>台輪: ¥{storage.baseRingPrice.toLocaleString()}</span>}
              {storage.mirrorPrice > 0 && <span>ミラー: ¥{storage.mirrorPrice.toLocaleString()}</span>}
              {storage.fillerCount > 0 && <span>フィラー: ¥{(storage.fillerPrice * storage.fillerCount).toLocaleString()}</span>}
            </div>
          )}
        </div>
        <div className="bg-gray-50 px-3 py-1 rounded border border-gray-200 text-right flex items-baseline justify-end gap-2">
          <span className="text-sm font-bold text-gray-500">収納合計:</span>
          <span className={`text-3xl font-bold ${isNone ? 'text-gray-400' : 'text-blue-700'} font-['Inter']`}>¥{total.toLocaleString()}</span>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { DoorItem, DoorType, PriceRecord } from '../types';
import { DOOR_GROUPS, COLORS, SLIDING_HANDLES, HINGED_HANDLES, DOOR_SPEC_MASTER, getFrameType, getDoorDetailPdfUrl } from '../constants';

interface DoorRowProps {
  index: number;
  door: DoorItem;
  updateDoor: (id: string, updates: Partial<DoorItem>) => void;
  removeDoor: (id: string) => void;
  initialSettings: {
    defaultHeight: string;
    defaultDoorColor: string;
    defaultHandleColor: string;
  };
  onShowHandleImage: () => void;
  siteName: string;
  priceList: PriceRecord[];
}

export const DoorRow: React.FC<DoorRowProps> = ({ 
  index, 
  door, 
  updateDoor, 
  removeDoor, 
  initialSettings, 
  onShowHandleImage,
  siteName,
  priceList
}) => {
  const [isCustomSizeInfoOpen, setIsCustomSizeInfoOpen] = useState(false);
  const [isFrameOptionOpen, setIsFrameOptionOpen] = useState(false);

  const spec = DOOR_SPEC_MASTER[door.type] || { designs: [], widths: [], hangingSides: ["なし"] };
  const isFoldingOrStorage = door.type.includes("折戸") || door.type.includes("物入");
  const isSliding = door.type.includes("引") || door.type.includes("引き");
  const isStorage = door.type === DoorType.StorageDouble || door.type === DoorType.StorageSingle;

  const standardHeights = isStorage 
    ? ["H900", "H1200", "H2000", "H2200", "H2400"] 
    : ["H2000", "H2200", "H2400"];

  const availableHeights = [...standardHeights, "特寸"];
  const availableWidths = [...spec.widths, "特寸"];

  const getAvailableHandleColors = () => {
    if (isFoldingOrStorage) return ["J型取手"];
    if (isSliding) return SLIDING_HANDLES;
    return HINGED_HANDLES;
  };

  const calculatePrice = (type: string, design: string, height: string, customHeight?: number) => {
    let effectiveHeight = height;
    if (height === '特寸' && customHeight) {
      if (isStorage) {
        if (customHeight <= 900) effectiveHeight = "H900";
        else if (customHeight <= 1200) effectiveHeight = "H1200";
        else if (customHeight <= 2000) effectiveHeight = "H2000";
        else if (customHeight <= 2200) effectiveHeight = "H2200";
        else effectiveHeight = "H2400";
      } else {
        if (customHeight <= 2000) effectiveHeight = "H2000";
        else if (customHeight <= 2200) effectiveHeight = "H2200";
        else effectiveHeight = "H2400";
      }
    }
    const record = priceList.find(p => p.type === type && p.design === design && p.height === effectiveHeight);
    if (record) return record.setPrice;
    const fallbackRecord = priceList.find(p => p.type === type && p.height === effectiveHeight);
    return fallbackRecord ? fallbackRecord.setPrice : 30000;
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target as HTMLInputElement;
    let updates: Partial<DoorItem> = {};

    if (type === 'checkbox') {
      const checked = (e.target as HTMLInputElement).checked;
      updates = { [name]: checked };
      if (name === 'isFrameExtended' && checked && !door.domaExtensionType) {
        updates.domaExtensionType = 'none';
      }
    } else {
       updates = { [name]: value };
    }

    if (name === 'type') {
      const newSpec = DOOR_SPEC_MASTER[value];
      if (newSpec) {
        updates.design = newSpec.designs[0];
        updates.width = newSpec.widths[0];
        updates.hangingSide = newSpec.hangingSides[0];
        const nextIsFoldingOrStorage = value.includes("折戸") || value.includes("物入");
        const nextIsSliding = value.includes("引") || value.includes("引き");
        if (nextIsFoldingOrStorage) updates.handleColor = "J型取手";
        else if (nextIsSliding) updates.handleColor = SLIDING_HANDLES[0];
        else updates.handleColor = HINGED_HANDLES[0];
        const nextIsStorage = value === DoorType.StorageDouble || value === DoorType.StorageSingle;
        const nextAvailableHeights = nextIsStorage 
          ? ["H900", "H1200", "H2000", "H2200", "H2400", "特寸"] 
          : ["H2000", "H2200", "H2400", "特寸"];
        let nextHeight = door.height;
        if (!nextAvailableHeights.includes(door.height)) {
          nextHeight = nextAvailableHeights.includes(initialSettings.defaultHeight) ? initialSettings.defaultHeight : "H2000";
          updates.height = nextHeight;
        }
        updates.frameType = getFrameType(value, nextHeight === '特寸' ? 'H2400' : nextHeight);
        updates.price = calculatePrice(value, updates.design || door.design, nextHeight, door.customHeight);
      }
    } else if (name === 'height') {
      if (value === '特寸') {
        updates.customHeight = door.customHeight || 2250;
        setIsCustomSizeInfoOpen(true);
      }
      updates.frameType = getFrameType(door.type, value === '特寸' ? 'H2400' : value);
      updates.price = calculatePrice(door.type, door.design, value, updates.customHeight || door.customHeight);
    } else if (name === 'width') {
      if (value === '特寸') {
        updates.customWidth = door.customWidth || 800;
        setIsCustomSizeInfoOpen(true);
      }
    } else if (name === 'customHeight') {
      const val = Math.min(2400, parseInt(value) || 0);
      updates.customHeight = val;
      updates.price = calculatePrice(door.type, door.design, door.height, val);
    } else if (name === 'customWidth') {
      updates.customWidth = parseInt(value) || 0;
    } else if (name === 'design') {
      updates.price = calculatePrice(door.type, value, door.height, door.customHeight);
    } else if (name === 'undercutHeight') {
       updates.undercutHeight = parseInt(value) || 0;
    } else if (name === 'frameExtensionHeight') {
       updates.frameExtensionHeight = parseInt(value) || 0;
    }
    updateDoor(door.id, updates);
  };

  const isDesignHighlighted = door.design !== "フラット";
  const isWidthHighlighted = door.width === "特寸";
  const isHeightHighlighted = door.height === "特寸" || door.height !== initialSettings.defaultHeight;
  const isFrameHighlighted = door.isUndercut || door.isFrameExtended;
  const isDoorColorHighlighted = door.doorColor !== initialSettings.defaultDoorColor;
  const isFrameColorHighlighted = door.frameColor !== initialSettings.defaultDoorColor;
  const isHandleColorHighlighted = door.handleColor !== "J型取手" && !door.handleColor.includes(initialSettings.defaultHandleColor);

  const getHighlightStyle = (isHighlighted: boolean) => isHighlighted ? 'color: #ef4444; font-weight: bold;' : '';
  const getTailwindHighlight = (isHighlighted: boolean) => isHighlighted ? 'text-red-600 font-bold bg-red-50 border-red-200' : '';

  const handleOpenDetails = () => {
    let finalUrl = '';
    let isPdf = false;

    // 適切な高度判定
    let effectiveHeight = door.height;
    if (door.height === '特寸' && door.customHeight) {
      if (isStorage) {
        if (door.customHeight <= 900) effectiveHeight = "H900";
        else if (door.customHeight <= 1200) effectiveHeight = "H1200";
        else if (door.customHeight <= 2000) effectiveHeight = "H2000";
        else if (door.customHeight <= 2200) effectiveHeight = "H2200";
        else effectiveHeight = "H2400";
      } else {
        if (door.customHeight <= 2000) effectiveHeight = "H2000";
        else if (door.customHeight <= 2200) effectiveHeight = "H2200";
        else effectiveHeight = "H2400";
      }
    }

    // 検索ロジック強化
    const record = priceList.find(p => p.type === door.type && p.design === door.design && p.height === effectiveHeight)
                || priceList.find(p => p.type === door.type && p.height === effectiveHeight);

    if (record && record.imageUrl) {
      finalUrl = record.imageUrl;
    } else {
      finalUrl = getDoorDetailPdfUrl(door);
    }

    isPdf = finalUrl.toLowerCase().endsWith('.pdf');

    const wdText = `WD-${index + 1}`;

    const widthHtml = door.width === '特寸' 
      ? `<span style="color: #ef4444; font-weight: bold;">${door.customWidth}㎜特寸</span>` 
      : `${door.width}`;

    const heightHtml = door.height === '特寸' 
      ? `<span style="color: #ef4444; font-weight: bold;">${door.customHeight}㎜特寸</span>` 
      : `<span style="${getHighlightStyle(door.height !== initialSettings.defaultHeight)}">${door.height.replace('H', '')}</span>`;

    const frameOptionText = [];
    if (door.isUndercut) frameOptionText.push(`アンダーカット${door.undercutHeight}㎜`);
    if (door.isFrameExtended) {
      if (door.domaExtensionType === 'none') frameOptionText.push('土間納まり(伸長なし)');
      else if (door.domaExtensionType === 'frame') frameOptionText.push(`土間納まり(枠伸長${door.frameExtensionHeight}㎜)`);
      else if (door.domaExtensionType === 'door') frameOptionText.push(`土間納まり(建具伸長${door.frameExtensionHeight}㎜)`);
    }

    const frameOptionHtml = frameOptionText.length > 0
      ? `<span style="color: #ef4444; margin-left: 0.5em; font-weight: bold;">(${frameOptionText.join(' / ')})</span>`
      : '';

    const printWindow = window.open('', '_blank');
    if (!printWindow) {
      alert('ポップアップがブロックされました。ブラウザの設定を確認してください。');
      return;
    }

    const htmlContent = `
      <!DOCTYPE html>
      <html lang="ja">
      <head>
        <meta charset="UTF-8">
        <title>詳細図面 - ${wdText}</title>
        <style>
          @page { size: A3 landscape; margin: 0; }
          body { 
            margin: 0; 
            padding: 0; 
            background: #eee;
            -webkit-print-color-adjust: exact; 
            print-color-adjust: exact; 
            font-family: 'Noto Sans JP', sans-serif;
            overflow: hidden;
          }
          .page-container {
            width: 420mm;
            height: 297mm;
            position: relative;
            background-color: white;
            margin: 0 auto;
            overflow: hidden;
          }
          .background-media {
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            z-index: 1;
          }
          .background-image {
            width: 100%;
            height: 100%;
            background-image: url('${finalUrl}');
            background-size: contain;
            background-repeat: no-repeat;
            background-position: center;
          }
          .background-pdf {
            width: 100%;
            height: 100%;
            border: none;
          }
          .overlay-header {
            position: absolute;
            top: 3mm;
            left: 5mm;
            display: flex;
            align-items: flex-start;
            gap: 2mm;
            z-index: 100;
          }
          .wd-box {
            padding: 1mm 4mm;
            font-size: 24pt;
            font-weight: bold;
            color: #1d4ed8;
            display: flex;
            align-items: center;
            justify-content: center;
            background: transparent;
            border: 2px solid #1d4ed8;
            border-radius: 4px;
          }
          .details-box {
            margin-top: 1mm;
            padding: 1mm 3mm;
            display: flex;
            flex-direction: column;
            justify-content: center;
            gap: 0.5mm;
            background: transparent;
          }
          .details-row {
            display: flex;
            align-items: baseline;
            gap: 4mm;
          }
          .details-item {
            display: flex;
            align-items: baseline;
            gap: 1.5mm;
          }
          .details-label {
            color: #666;
            font-size: 8pt;
            white-space: nowrap;
          }
          .details-value {
            font-weight: bold;
            font-size: 10pt;
            color: #000;
            white-space: nowrap;
            line-height: 1.2;
          }
          .no-print-bar {
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            background: #1f2937;
            color: white;
            padding: 10px 20px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            z-index: 1000;
          }
          .print-btn {
            background: #2563eb;
            color: white;
            border: none;
            padding: 10px 24px;
            border-radius: 6px;
            cursor: pointer;
            font-weight: bold;
            font-size: 14px;
          }
          @media print {
            .no-print-bar { display: none; }
            body { background: white; }
            .page-container { margin: 0; }
          }
        </style>
      </head>
      <body>
        <div class="no-print-bar">
          <span>図面プレビュー: ${wdText} (${siteName || '現場名未設定'})</span>
          <button class="print-btn" onclick="window.print()">印刷 / PDF保存</button>
        </div>
        <div class="page-container">
          <div class="background-media">
            ${isPdf 
              ? `<iframe src="${finalUrl}#toolbar=0&navpanes=0&scrollbar=0&view=FitH" class="background-pdf"></iframe>`
              : `<div class="background-image"></div>`
            }
          </div>
          <div class="overlay-header">
            <div class="wd-box">${wdText}</div>
            <div class="details-box">
              <div class="details-row">
                <div class="details-item"><span class="details-label">物件名</span><span class="details-value">${siteName || ''}</span></div>
                <div class="details-item"><span class="details-label">部屋名</span><span class="details-value">${door.roomName || ''}</span></div>
                <div class="details-item"><span class="details-label">種類</span><span class="details-value">${door.type}</span></div>
                <div class="details-item"><span class="details-label">デザイン</span><span class="details-value" style="${getHighlightStyle(isDesignHighlighted)}">${door.design}</span></div>
                <div class="details-item"><span class="details-label">サイズ</span><span class="details-value">${widthHtml}×${heightHtml}</span></div>
              </div>
              <div class="details-row">
                <div class="details-item"><span class="details-label">枠仕様</span><span class="details-value" style="${getHighlightStyle(isFrameHighlighted)}">${door.frameType}${frameOptionHtml}</span></div>
                <div class="details-item"><span class="details-label">吊元</span><span class="details-value">${door.hangingSide}</span></div>
                <div class="details-item"><span class="details-label">扉色</span><span class="details-value" style="${getHighlightStyle(isDoorColorHighlighted)}">${door.doorColor}</span></div>
                <div class="details-item"><span class="details-label">枠色</span><span class="details-value" style="${getHighlightStyle(isFrameColorHighlighted)}">${door.frameColor}</span></div>
                <div class="details-item"><span class="details-label">ハンドル</span><span class="details-value" style="${getHighlightStyle(isHandleColorHighlighted)}">${door.handleColor}</span></div>
              </div>
            </div>
          </div>
        </div>
      </body>
      </html>
    `;

    printWindow.document.write(htmlContent);
    printWindow.document.close();
  };

  return (
    <tr className="border-b border-gray-200 hover:bg-gray-50 transition-colors text-[11px]">
      <td className="p-2 font-medium text-gray-500 text-center border-r border-gray-100">WD{index + 1}</td>
      <td className="p-1">
        <input type="text" name="roomName" value={door.roomName} onChange={handleChange} className="w-full border rounded px-1 py-1 h-8" placeholder="部屋名" />
      </td>
      <td className="p-1">
        <select name="type" value={door.type} onChange={handleChange} className="w-full border rounded px-1 py-1 h-8 font-semibold text-gray-700">
          {DOOR_GROUPS.map(group => (
            <optgroup key={group.label} label={group.label}>
              {group.options.map(option => (
                <option key={option} value={option}>{option}</option>
              ))}
            </optgroup>
          ))}
        </select>
      </td>
      <td className="p-1">
        <select name="design" value={door.design} onChange={handleChange} className={`w-full border rounded px-1 py-1 h-8 ${getTailwindHighlight(isDesignHighlighted)}`}>
          {spec.designs.map(d => <option key={d} value={d}>{d}</option>)}
        </select>
      </td>
      <td className="p-1">
        <div className="flex flex-col gap-1 min-w-[70px]">
          <select name="width" value={door.width} onChange={handleChange} className={`w-full border rounded px-1 py-1 h-8 ${getTailwindHighlight(isWidthHighlighted)}`}>
            {availableWidths.map(w => <option key={w} value={w}>{w === '特寸' ? '特寸' : `${w}mm`}</option>)}
          </select>
          {door.width === '特寸' && (
            <div className="flex items-center gap-1 text-red-600 font-bold">
              <input type="number" name="customWidth" value={door.customWidth} onChange={handleChange} className="w-full border border-red-200 rounded px-1 h-6 bg-white" />
              <span className="text-[10px]">㎜</span>
            </div>
          )}
        </div>
      </td>
      <td className="p-1">
        <div className="flex flex-col gap-1 min-w-[70px]">
